import java.io.IOException;

public class CommandInjectionExample {

    public static void main(String[] args) {
        String userInput = "ls -la";

        try {
            // Split the user input into separate arguments
            String[] command = userInput.split(" ");

            // Create ProcessBuilder with the command arguments
            ProcessBuilder processBuilder = new ProcessBuilder(command);

            // Start the process
            Process process = processBuilder.start();

            // Do something with the process output...
        } catch (IOException e) {
            System.out.println("An error occurred while executing the command.");
        }
    }
}

